136	// Get all team info
137	function getTeams() {
138	  const teams = [];
139	  if (!fs.existsSync(TEAMS_DIR)) return teams;
140	
141	  const teamDirs = fs.readdirSync(TEAMS_DIR);
142	
143	  for (const teamName of teamDirs) {
144	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
145	    try {
146	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
147	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
148	
149	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
150	      if (fs.existsSync(taskListPath)) {
151	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
152	        for (const taskFile of taskFiles) {
153	          try {
154	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
155	            taskStatus.total++;
156	            if (task.status === 'completed') taskStatus.completed++;
157	            else if (task.status === 'in_progress') taskStatus.inProgress++;
158	            else if (task.status === 'pending') taskStatus.pending++;
159	          } catch {}
160	        }
161	      }
162	
163	      teams.push({
164	        name: teamName,
165	        description: config.description || '',
166	        memberCount: config.members?.length || 0,
167	        taskStatus
168	      });
169	    } catch {}
170	  }
171	
172	  return teams;
173	}
