175	// Build environment from user settings
176	function buildEnvScript() {
177	  let settingsEnv = {};
178	  try {
179	    const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
180	    const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
181	    settingsEnv = settings.env || {};
182	  } catch (e) {
183	    console.error('Could not read settings.json:', e.message);
184	  }
185	
186	  return {
187	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: settingsEnv.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS || '1',
188	    ANTHROPIC_BASE_URL: settingsEnv.ANTHROPIC_BASE_URL || '',
189	    ANTHROPIC_AUTH_TOKEN: settingsEnv.ANTHROPIC_AUTH_TOKEN || '',
190	    ANTHROPIC_API_KEY: settingsEnv.ANTHROPIC_API_KEY || '',
191	    ANTHROPIC_MODEL: settingsEnv.ANTHROPIC_MODEL || '',
192	    CLAUDE_BIN: settingsEnv.CLAUDE_BIN || path.join(process.env.HOME, '.local', 'bin', 'claude')
193	  };
194	}
