196	// Check if Claude CLI works (detects context management incompatibility)
197	let claudeCompatible = null; // null = not yet checked, boolean = cached
198	
199	function checkClaudeCompatibility() {
200	  if (claudeCompatible !== null) return claudeCompatible;
201	  const env = buildEnvScript();
202	  try {
203	    execSync(`"${env.CLAUDE_BIN}" --version`, { stdio: 'pipe' });
204	    // Try a quick API call to see if context management works
205	    execSync(
206	      `CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS='${env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS}' ` +
207	      `ANTHROPIC_BASE_URL='${env.ANTHROPIC_BASE_URL}' ` +
208	      `ANTHROPIC_AUTH_TOKEN='${env.ANTHROPIC_AUTH_TOKEN}' ` +
209	      `ANTHROPIC_API_KEY='${env.ANTHROPIC_API_KEY}' ` +
210	      `ANTHROPIC_MODEL='${env.ANTHROPIC_MODEL}' ` +
211	      `CLAUDECODE='' "${env.CLAUDE_BIN}" --print -p "hi" 2>&1`,
212	      { stdio: 'pipe', timeout: 15000 }
213	    );
214	    claudeCompatible = true;
215	    return true;
216	  } catch (e) {
217	    claudeCompatible = false;
218	    return false;
219	  }
220	}
