222	// Parse CLI args string into array (handles --flag and "quoted strings")
223	function parseCliArgs(input) {
224	  const args = [];
225	  let current = '';
226	  let inQuote = false;
227	
228	  for (let i = 0; i < input.length; i++) {
229	    const c = input[i];
230	    if (c === '"' && !inQuote) {
231	      inQuote = true;
232	    } else if (c === '"' && inQuote) {
233	      inQuote = false;
234	      args.push(current);
235	      current = '';
236	    } else if (c === ' ' && !inQuote) {
237	      if (current) args.push(current);
238	      current = '';
239	    } else {
240	      current += c;
241	    }
242	  }
243	  if (current) args.push(current);
244	  return args;
245	}
