247	// Spawn a detached background claude process
248	function spawnBackgroundProcess(name, cmd) {
249	  const env = buildEnvScript();
250	  const logFile = path.join(__dirname, `logs/${name}-${Date.now()}.log`);
251	  const logsDir = path.join(__dirname, 'logs');
252	  if (!fs.existsSync(logsDir)) fs.mkdirSync(logsDir, { recursive: true });
253	
254	  const parts = parseCliArgs(cmd);
255	
256	  // Build a clean environment — omit CLAUDECODE to prevent nested-session rejection
257	  const cleanEnv = {
258	    ...process.env,
259	    CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS: env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS,
260	    ANTHROPIC_BASE_URL: env.ANTHROPIC_BASE_URL,
261	    ANTHROPIC_AUTH_TOKEN: env.ANTHROPIC_AUTH_TOKEN,
262	    ANTHROPIC_API_KEY: env.ANTHROPIC_API_KEY,
263	    ANTHROPIC_MODEL: env.ANTHROPIC_MODEL
264	  };
265	  delete cleanEnv.CLAUDECODE;
266	  delete cleanEnv.CLAUDE_CODE_SSE_PORT;
267	  delete cleanEnv.CLAUDE_CODE_ENTRYPOINT;
268	
269	  try {
270	    const child = spawn(env.CLAUDE_BIN, parts, {
271	      detached: true,
272	      stdio: ['ignore', 'pipe', 'pipe'],
273	      env: cleanEnv
274	    });
275	
276	    const logStream = fs.createWriteStream(logFile, { flags: 'a' });
277	    child.stdout.pipe(logStream);
278	    child.stderr.pipe(logStream);
279	
280	    child.unref();
281	    return { pid: child.pid, logFile };
282	  } catch (e) {
283	    console.error('Spawn failed:', e.message);
284	    return { pid: null, logFile, error: e.message };
285	  }
286	}
