298	// API: Wake up a team by re-spawning the agent in background
299	app.post('/api/wake/:name', (req, res) => {
300	  try {
301	    const teamName = req.params.name;
302	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
303	
304	    if (!fs.existsSync(teamConfigPath)) {
305	      return res.status(404).json({ success: false, error: 'Team not found' });
306	    }
307	
308	    const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
309	    if (!config.members || config.members.length === 0) {
310	      return res.status(400).json({ success: false, error: 'Team has no members' });
311	    }
312	
313	    // Check if Claude CLI is compatible with the current API provider
314	    const canSpawn = checkClaudeCompatibility();
315	
316	    let results = [];
317	
318	    for (const member of config.members) {
319	      const { name, agentType } = member;
320	
321	      if (!canSpawn) {
322	        // Mark as active without spawning — user needs to resume manually
323	        member.backgroundId = `${name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-manual`;
324	        results.push({
325	          name: member.name,
326	          logFile: null,
327	          status: 'registered',
328	          note: 'OpenRouter requires manual resume. Run: claude -r ' + teamName
329	        });
330	        continue;
331	      }
332	
333	      let cmd;
334	      if (name.toLowerCase() === 'trevor' || agentType === 'manager' || agentType === 'trevor') {
335	        cmd = '--agent=trevor -p "Resume your previous work as manager agent."';
336	      } else {
337	        cmd = `-p "Wake up agent ${name}, continue previous work."`;
338	      }
339	
340	      const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
341	      const backgroundId = `${safeName}-${Date.now()}`;
342	      const { pid, logFile } = spawnBackgroundProcess(backgroundId, cmd);
343	
344	      if (pid) savePid(`${teamName}.pid`, pid);
345	      console.log(`Woke up ${name} (PID: ${pid})`);
346	
347	      member.backgroundId = backgroundId;
348	      results.push({ name: member.name, logFile, status: 'waking_up' });
349	    }
350	
351	    fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));
352	
353	    res.json({ success: true, message: `Woke up team "${teamName}"`, agents: results, canSpawn });
354	  } catch (err) {
355	    res.status(500).json({ success: false, error: err.message });
356	  }
357	});
