382	// API: Spawn agent
383	// Since OpenRouter doesn't support Claude CLI context management,
384	// this creates a registered agent entry that users can manage from the dashboard.
385	// Status shows as "registered" — users can resume the session manually.
386	app.post('/api/spawn', (req, res) => {
387	  try {
388	    const { name, role, prompt, description } = req.body;
389	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
390	
391	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
392	    const teamName = `agent-${safeName}-${Date.now()}`;
393	    const backgroundId = `spawn-${safeName}-${Date.now()}`;
394	
395	    const canSpawn = checkClaudeCompatibility();
396	    let logFile = null;
397	    let pid = null;
398	
399	    if (canSpawn) {
400	      // Build the claude command
401	      let cmd;
402	      if (name.toLowerCase() === 'trevor' || role === 'manager' || role === 'trevor') {
403	        cmd = `--agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
404	      } else {
405	        cmd = `"${fullPrompt.replace(/"/g, '\\"')}"`;
406	      }
407	
408	      const result = spawnBackgroundProcess(backgroundId, cmd);
409	      pid = result.pid;
410	      logFile = result.logFile;
411	    }
412	
413	    if (pid) savePid(`${teamName}.pid`, pid);
414	
415	    // Save description
416	    if (description) {
417	      const descriptions = loadDescriptions();
418	      descriptions[name] = description;
419	      saveDescriptions(descriptions);
420	    }
421	
422	    // Create team entry so the dashboard can discover this agent
423	    const teamDir = path.join(TEAMS_DIR, teamName);
424	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
425	
426	    fs.mkdirSync(teamDir, { recursive: true });
427	    fs.mkdirSync(taskListDir, { recursive: true });
428	
429	    const teamConfig = {
430	      description: description || `${name} — ${role} agent`,
431	      leaderSessionId: null,
432	      createdAt: Date.now(),
433	      backgroundId,
434	      members: [{
435	        agentId: `agent-${safeName}`,
436	        name,
437	        agentType: role || 'general-purpose',
438	        backgroundId
439	      }]
440	    };
441	    fs.writeFileSync(
442	      path.join(teamDir, 'config.json'),
443	      JSON.stringify(teamConfig, null, 2)
444	    );
445	
446	    res.json({
447	      success: true,
448	      message: canSpawn
449	        ? `Agent "${name}" spawned in background`
450	        : `Agent "${name}" registered (OpenRouter — resume manually)`,
451	      name,
452	      teamName,
453	      logFile,
454	      canSpawn,
455	      resumeCommand: canSpawn ? null : `claude -r ${teamName}`
456	    });
457	  } catch (err) {
458	    res.status(500).json({ success: false, error: err.message });
459	  }
460	});
