497	// Open a new Terminal.app tab and run a command via osascript
498	// Writes command to .sh + AppleScript to temp files to avoid all quoting issues
499	function openTerminalTab(title, command) {
500	  const tmpDir = path.join(__dirname, '.tmp');
501	  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
502	
503	  // Write the actual command to a shell script
504	  const shellFile = path.join(tmpDir, `launch-${Date.now()}.sh`);
505	  fs.writeFileSync(shellFile, `#!/bin/bash\necho "=== Agent: ${title} ==="\n${command}\n`, 'utf8');
506	  fs.chmodSync(shellFile, '755');
507	
508	  // Escape the path for AppleScript (no quotes needed if no spaces in tmp path)
509	  const safeShellPath = shellFile.replace(/"/g, '\\"').replace(/\\/g, '\\\\');
510	  const safeTitle = title.replace(/"/g, '\\"');
511	
512	  const appleScript = `tell application "Terminal"
513	    set winId to do script "${safeShellPath}"
514	    set custom title of winId to "${safeTitle}"
515	    set title displays custom title of winId to true
516	    set miniaturized of winId to true
517	end tell
518	`;
519	  const scriptFile = path.join(tmpDir, `launch-${Date.now()}.scpt`);
520	  fs.writeFileSync(scriptFile, appleScript, 'utf8');
521	
522	  try {
523	    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 10000 });
524	    // Clean up after a delay (Terminal has already sourced the files)
525	    setTimeout(() => {
526	      try { fs.unlinkSync(shellFile); } catch {}
527	      try { fs.unlinkSync(scriptFile); } catch {}
528	    }, 10000);
529	    return true;
530	  } catch (e) {
531	    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
532	    try { fs.unlinkSync(shellFile); } catch {}
533	    try { fs.unlinkSync(scriptFile); } catch {}
534	    return false;
535	  }
536	}
