539	app.post('/api/launch/:name', (req, res) => {
540	  try {
541	    const teamName = req.params.name;
542	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
543	
544	    if (!fs.existsSync(teamConfigPath)) {
545	      return res.status(404).json({ success: false, error: 'Team not found' });
546	    }
547	
548	    const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
549	    const member = config.members[0];
550	    const claudePath = path.join(process.env.HOME, '.local', 'bin', 'claude');
551	    const isTrevor = member.name.toLowerCase() === 'trevor';
552	    let cmd = `cd "${__dirname}" && CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 ${claudePath} -r ${teamName}`;
553	    if (isTrevor) cmd += ' --agent=trevor';
554	    cmd += ' --permission-mode acceptEdits';
555	
556	    // Mark as launched and save PID for status tracking
557	    member.backgroundId = `${member.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-launched-${Date.now()}`;
558	    const safePidName = `${teamName}.pid`;
559	    // Save current PID so status check can see this agent is "alive"
560	    // We use the server process PID as a proxy — if dashboard server is running, agent is reachable
561	    savePid(safePidName, process.pid);
562	    fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));
563	
564	    const opened = openTerminalTab(member.name, cmd);
565	
566	    if (opened) {
567	      res.json({ success: true, message: `${member.name} opened in Terminal` });
568	    } else {
569	      // Fallback: return the command so the user can run it manually
570	      res.json({ success: true, message: `${member.name} — Terminal open failed, run manually:`, command: cmd });
571	    }
572	  } catch (err) {
573	    res.status(500).json({ success: false, error: err.message });
574	  }
575	});
