577	// API: Generate launch script that opens all agents in Terminal.app
578	app.get('/api/launch-script', (req, res) => {
579	  const agents = getRunningAgents();
580	  if (agents.length === 0) {
581	    return res.status(204).send('No agents to launch');
582	  }
583	
584	  const claudePath = path.join(process.env.HOME, '.local', 'bin', 'claude');
585	
586	  let script = `#!/bin/bash\n# Agent Office — Launch All Agents\n`;
587	  script += `cd "${__dirname}"\n`;
588	  script += `export CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1\n\n`;
