1271	  font-size: 0.6rem;
1272	  color: #fff;
1273	  animation: scrollText 10s steps(40) infinite;
1274	  white-space: nowrap;
1275	  overflow: hidden;
1276	  text-overflow: ellipsis;
1277	}
1278	
1279	@keyframes scrollText {
1280	  0%, 95% { opacity: 1; }
1281	  96%, 100% { opacity: 0; }
1282	}
1283	
1284	/* --- Modal --- */
1285	.modal {
1286	  display: none;
1287	  position: fixed;
1288	  inset: 0;
1289	  background: rgba(0,0,0,0.85);
1290	  z-index: 100;
1291	  align-items: center;
1292	  justify-content: center;
1293	  padding: 24px;
1294	}
1295	
1296	.modal.visible {
1297	  display: flex;
1298	}
1299	
1300	.modal-content {
1301	  background: var(--panel-bg);
1302	  border: var(--border-thick) solid var(--panel-border);
1303	  max-width: 500px;
1304	  width: 100%;
1305	  max-height: 90vh;
1306	  overflow-y: auto;
1307	}
1308	
1309	/* Pokemon battle box style border */
1310	.pixel-box {
1311	  position: relative;
1312	  box-shadow:
1313	    4px 4px 0 rgba(0,0,0,0.4),
1314	    inset 2px 2px 0 #fff,
1315	    inset -2px -2px 0 #aaa;
1316	}
1317	
1318	.pixel-box::after {
1319	  content: '';
1320	  position: absolute;
1321	  inset: 4px;
1322	  border: var(--border-thin) solid var(--panel-border);
