501	// Draw agent sprite (pixel character) with agent-specific skins
502	function drawAgentSprite(agent, screenX, screenY) {
503	  const name = agent.name.toLowerCase();
504	
505	  // Draw agent-specific body
506	  switch (name) {
507	    case 'trevor': drawTrevorSprite(screenX, screenY); break;
508	    case 'luca': drawLucaSprite(screenX, screenY); break;
509	    case 'ellie': drawEllieSprite(screenX, screenY); break;
510	    case 'mateo': drawMateoSprite(screenX, screenY); break;
511	    default: drawGenericSprite(agent, screenX, screenY); break;
512	  }
513	
514	  // Status indicator (top-right) — colored dot based on session state
515	  const dotX = screenX + TILE - 6;
516	  const dotY = screenY - 4;
517	  if (agent.processAlive) {
518	    // Actively processing
519	    ctx.fillStyle = '#4caf50';
520	    ctx.fillRect(dotX, dotY, 5, 5);
521	  } else if (agent.isLaunched) {
522	    // Idle — Terminal open but not actively responding
523	    const pulse = Math.sin(Date.now() / 400) * 0.3 + 0.5;
524	    ctx.globalAlpha = pulse;
525	    ctx.fillStyle = '#ffc400';
526	    ctx.fillRect(dotX, dotY, 5, 5);
527	    ctx.globalAlpha = 1;
528	  } else {
529	    // Not connected — red dot
530	    ctx.fillStyle = '#f44336';
531	    ctx.fillRect(dotX, dotY, 5, 5);
532	    // Zzz for not connected
533	    ctx.fillStyle = '#f44336';
534	    ctx.font = '6px "Press Start 2P", monospace';
535	    const zOff = Math.sin(Date.now() / 300) * 2;
536	    ctx.fillText('Z', screenX + TILE, screenY - 8 + zOff);
537	  }
538	
539	  // Name tag (always on top)
540	  ctx.fillStyle = '#2a2a4e';
541	  ctx.font = 'bold 7px "Press Start 2P", monospace';
542	  const nameWidth = ctx.measureText(agent.name).width;
543	  const tagX = screenX + (TILE - nameWidth - 6) / 2;
544	  const tagY = screenY - 2;
545	  ctx.fillRect(tagX - 1, tagY - 1, nameWidth + 8, 9);
546	  ctx.fillStyle = '#ffc400';
547	  ctx.fillText(agent.name, tagX + 3, tagY + 6);
548	}
