624	// Draw player
625	function drawPlayer() {
626	  const screenX = player.x * TILE - camX;
627	  const screenY = player.y * TILE - camY;
628	
629	  // Bob animation
630	  const bob = Math.sin(player.pixelBob) * 2;
631	
632	  // Shadow
633	  ctx.fillStyle = 'rgba(0,0,0,0.2)';
634	  ctx.beginPath();
635	  ctx.ellipse(screenX + TILE / 2, screenY + TILE + 2, 12, 4, 0, 0, Math.PI * 2);
636	  ctx.fill();
637	
638	  // Body
639	  ctx.fillStyle = '#e53935';
640	  ctx.fillRect(screenX + 14, screenY + 12 + bob, 20, 22);
641	  // Head
642	  ctx.fillStyle = '#fdd8a5';
643	  ctx.fillRect(screenX + 16, screenY + 2 + bob, 16, 14);
644	  // Hat (red cap like a Pokemon trainer)
645	  ctx.fillStyle = '#e53935';
646	  ctx.fillRect(screenX + 14, screenY - 2 + bob, 20, 6);
647	  ctx.fillRect(screenX + 14, screenY + 2 + bob, 26, 3);
648	  // Eyes
649	  ctx.fillStyle = '#1a1a2e';
650	  const eyeOffX = player.dir === 'left' ? -2 : player.dir === 'right' ? 2 : 0;
651	  const eyeOffY = player.dir === 'up' ? -4 : player.dir === 'down' ? 2 : 0;
652	  if (player.dir !== 'up') {
653	    ctx.fillRect(screenX + 19 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
654	    ctx.fillRect(screenX + 26 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
655	  }
656	  // Legs
657	  ctx.fillStyle = '#1565c0';
658	  ctx.fillRect(screenX + 14, screenY + 32 + bob, 8, 12);
659	  ctx.fillRect(screenX + 26, screenY + 32 + bob, 8, 12);
660	  // Shoes
661	  ctx.fillStyle = '#fff';
662	  ctx.fillRect(screenX + 12, screenY + 42 + bob, 10, 4);
663	  ctx.fillRect(screenX + 24, screenY + 42 + bob, 10, 4);
664	}
