675	// Main render loop
676	function render() {
677	  // Update player movement
678	  let dx = 0, dy = 0;
679	  const spd = player.speed;
680	  player.moving = false;
681	
682	  if (keys['w'] || keys['arrowup']) { dy = -spd; player.dir = 'up'; player.moving = true; }
683	  else if (keys['s'] || keys['arrowdown']) { dy = spd; player.dir = 'down'; player.moving = true; }
684	  else if (keys['a'] || keys['arrowleft']) { dx = -spd; player.dir = 'left'; player.moving = true; }
685	  else if (keys['d'] || keys['arrowright']) { dx = spd; player.dir = 'right'; player.moving = true; }
686	
687	  if (player.moving) {
688	    player.pixelBob += 0.15;
689	
690	    // Check X movement
691	    const newX = player.x + dx;
692	    if (isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.3)) &&
693	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.3)) &&
694	        isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.8)) &&
695	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.8))) {
696	      player.x = newX;
697	    }
698	
699	    // Check Y movement
700	    const newY = player.y + dy;
701	    if (isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.3)) &&
702	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.3)) &&
703	        isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.8)) &&
704	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.8))) {
705	      player.y = newY;
706	    }
707	  }
708	
709	  // Update camera to follow player
710	  camX = player.x * TILE - canvas.width / 2 + TILE / 2;
711	  camY = player.y * TILE - canvas.height / 2 + TILE / 2;
712	
713	  // Clamp camera
714	  camX = Math.max(0, Math.min(camX, COLS * TILE - canvas.width));
715	  camY = Math.max(0, Math.min(camY, ROWS * TILE - canvas.height));
716	
717	  // Clear
718	  ctx.clearRect(0, 0, canvasW, canvasH);
719	
720	  // Draw tiles
721	  const startCol = Math.max(0, Math.floor(camX / TILE));
722	  const startRow = Math.max(0, Math.floor(camY / TILE));
723	  const endCol = Math.min(COLS - 1, Math.ceil((camX + canvasW) / TILE));
724	  const endRow = Math.min(ROWS - 1, Math.ceil((camY + canvasH) / TILE));
725	
726	  for (let y = startRow; y <= endRow; y++) {
727	    for (let x = startCol; x <= endCol; x++) {
728	      const tile = officeMap[y][x];
729	      if (tile !== undefined) drawTile(x, y, tile);
730	    }
731	  }
732	
733	  // Draw sports floors on top of tiles
734	  drawSportsFloor();
735	
736	  // Draw agent sprites on their desks
737	  const agentPositions = getAgentPositions();
738	  agentPositions.forEach(({ x, y, agent }) => {
739	    const screenX = x * TILE - camX + 8;
740	    const screenY = y * TILE - camY + 8;
741	    drawAgentSprite(agent, screenX, screenY);
742	  });
743	
744	  // Draw player on top
745	  drawPlayer();
746	
747	  // Draw room labels as floor text
748	  ctx.fillStyle = 'rgba(255,255,255,0.3)';
749	  ctx.font = '4px "Press Start 2P", monospace';
750	
751	  // Check for interaction hint
752	  const tileAtPlayer = getTileAt(Math.floor(player.x + 0.5), Math.floor(player.y + 0.5));
753	  if (tileAtPlayer === 6) {
754	    showTooltip('Press E to interact');
755	  }
756	
757	  requestAnimationFrame(render);
