      ctx.fillStyle = '#8b6914';
      ctx.fillRect(screenX + 4, screenY + 8, TILE - 8, TILE - 16);
      // Desk top highlight
      ctx.fillStyle = '#a68527';
      ctx.fillRect(screenX + 6, screenY + 10, TILE - 12, TILE - 22);
